const PORTAL_ERROR_ABSOLUTE_THRESHOLD = 10

const PORTAL_ERROR_PERCENT_THRESHOLD = 0.2



let italyCitiesCache: ItalianCity[] | null = null

let italyProvincesCache: ItalianProvince[] | null = null



async function loadItalianCities() {

  if (italyCitiesCache) return italyCitiesCache



  if (typeof window !== 'undefined') {

    const cached = window.localStorage.getItem('italy_cities_v2')

    if (cached) {

      try {

        const parsed = JSON.parse(cached) as ItalianCity[]

        italyCitiesCache = parsed

        return parsed

      } catch {

      }

    }

  }



  const response = await fetch('https://raw.githubusercontent.com/matteocontrini/comuni-json/master/comuni.json')

  if (!response.ok) {

    throw new Error('Impossibile caricare la lista dei comuni italiani')

  }

  const rawData = await response.json()



  const cities: ItalianCity[] = (rawData as any[]).map(item => ({

    name: item.nome as string,

    provinceCode: item.sigla as string,

    provinceName: item.provincia?.nome || (item.sigla as string),

    regionName: item.regione?.nome as string,
    istatCode: String(item.codice || '')

  }))



  italyCitiesCache = cities



  if (typeof window !== 'undefined') {

    try {

      window.localStorage.setItem('italy_cities_v2', JSON.stringify(cities))

    } catch {

    }

  }



  return cities

}



async function loadItalianProvinces() {

  if (italyProvincesCache) return italyProvincesCache



  const cities = await loadItalianCities()

  const map = new Map<string, ItalianProvince>()



  for (const city of cities) {

    if (!map.has(city.provinceCode)) {

      map.set(city.provinceCode, {

        code: city.provinceCode,

        name: city.provinceName,

        regionName: city.regionName

      })

    }

  }



  const provinces = Array.from(map.values()).sort((a, b) => a.name.localeCompare(b.name, 'it'))

  italyProvincesCache = provinces

  return provinces

}



