  // Gestione contatti/clienti

  const handleCreateContact = async (contactData: Omit<Contact, 'id' | 'createdAt'>) => {

    try {

      // Prepare clean payload for backend (remove frontend-only fields and map names)

      const isClientType = ['BUYER', 'TENANT', 'LEAD'].includes(contactData.type)

      const payload: any = {

        firstName: contactData.firstName,

        lastName: contactData.lastName,

        email: contactData.email,

        phone: contactData.phone,

        type: contactData.type,

        city: contactData.city,

        province: contactData.province,

        address: contactData.address,

        zipCode: contactData.zipCode,

        birthDate: contactData.birthDate,

        birthPlace: (contactData as any).birthPlace,

        fiscalCode: contactData.fiscalCode,

        notes: contactData.notes,

        tags: contactData.tags,

        isActive: contactData.isActive,

        source: contactData.source,

        agencyId: user?.agency?.id

      }

      if (isClientType) {

        payload.requestApartmentType = contactData.requestApartmentType
        payload.requestPropertyType = (contactData as any).requestPropertyType
        payload.requestGoal = (contactData as any).requestGoal
        payload.requestZone = (contactData as any).requestZone
        payload.requestSurfaceSqm = (contactData as any).requestSurfaceSqm
        payload.rentContractSubtype = (contactData as any).rentContractSubtype

        payload.requestBedrooms = contactData.requestBedrooms

        payload.requestBathrooms = contactData.requestBathrooms

        payload.requestFloor = contactData.requestFloor

        payload.budget = contactData.budget

        payload.preferences = contactData.preferences

      }

      

      const isAdminRole = userRole === 'SUPER_ADMIN' || userRole === 'AGENCY_ADMIN'

      if (isAdminRole) {

        if (contactData.assignedAgent && contactData.assignedAgent.trim() !== '') {

          payload.assignedToId = contactData.assignedAgent

        }

      } else if (user?.id) {

        payload.assignedToId = user.id

      }

      

      const response = await fetch('/api/contacts', {

        method: 'POST',

        headers: { 'Content-Type': 'application/json' },

        body: JSON.stringify(payload)

      })



      const data = await response.json()

      if (data.success) {

        // Aggiungi category alla risposta per lo stato locale

        const newContact = {

          ...data.data,

          category: ['BUYER', 'TENANT', 'LEAD'].includes(data.data.type) ? 'CLIENT' : 'PROPRIETOR',

          assignedAgent: contactData.assignedAgent || data.data.assignedAgent || data.data.assignedToId || undefined

        }

        

        // Aggiorna la lista contatti

        setContacts(prev => [newContact, ...prev])



        // Create notification for new client

        const clientType = contactData.type === 'BUYER' ? 'Cerca appartamento da acquistare' :

          contactData.type === 'SELLER' ? 'Venditore' :

            contactData.type === 'TENANT' ? 'Cerca appartamento in affitto' : 'Proprietario'

        createNotification(

          'CLIENT_ADDED',

          ' Nuovo Cliente',

          `${contactData.firstName} ${contactData.lastName} - ${clientType}`,

          data.data.id

        )

        return newContact

      } else {
        const validationErrors = Array.isArray(data?.errors)
          ? data.errors
              .map((item: unknown) => (typeof item === 'string' ? item.trim() : ''))
              .filter(Boolean)
          : []
        const details = [
          data?.error ? String(data.error) : '',
          validationErrors.length ? validationErrors.join('\n') : ''
        ]
          .filter(Boolean)
          .join('\n')
        const message = data?.message ? String(data.message) : 'Errore nella creazione contatto'
        alert(`Errore nella creazione contatto: ${message}${details ? `\n\nDettagli:\n${details}` : ''}`)
        return null

      }

    } catch (error) {

      console.error('Errore nella creazione contatto:', error)

      alert('Errore di connessione durante la creazione del contatto')

      return null

    }

  }



